(
  sum by (hostname, instance) (
    rate(om_client_protocol_time{instance=~"$instance",type=~"^(CreateVolume|SetVolumeProperty|CheckVolumeAccess|InfoVolume|DeleteVolume|ListVolume)$"}[$__rate_interval])
  )
  /
  sum by (hostname, instance) (
    clamp_min(rate(om_client_protocol_counter{instance=~"$instance",type=~"^(CreateVolume|SetVolumeProperty|CheckVolumeAccess|InfoVolume|DeleteVolume|ListVolume)$"}[$__rate_interval]), 1e-12)
  )
)

